package com.panini.back.controller; import com.panini.back.entity.Sticker; import com.panini.back.service.StickerService; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController @RequestMapping("/api/stickers") public class StickerController { private final StickerService service; public StickerController(StickerService service){ this.service=service; } @GetMapping public List<Sticker> getAll(@RequestParam(required=false) String search, @RequestParam(required=false) String category, @RequestParam(required=false) String country){ if(category!=null && !category.isBlank()) return service.byCategory(category); if(country!=null && !country.isBlank()) return service.byCountry(country); return service.search(search); } }
